SELECT comment_id, reason
FROM comment_flags
WHERE flag_id = 1;

SELECT mentioned_user_id, COUNT(*) AS mention_count
FROM comment_mentions
GROUP BY mentioned_user_id;

SELECT user_id, created_on
FROM comment_mentions
WHERE user_id = 0 AND mentioned_user_id = 1;

SELECT COUNT(*)
FROM comment_votes
WHERE vote_type = 'downvote';

SELECT user_id, COUNT(*) AS report_count
FROM comment_reports
GROUP BY user_id;
